<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Falling Sand Sandbox</title>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    background: #1a1a2e;
    color: #e0e0e0;
    font-family: 'Segoe UI', system-ui, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    overflow: hidden;
    user-select: none;
  }
  h1 {
    font-size: 1.4rem;
    margin-bottom: 12px;
    color: #c8d6e5;
    letter-spacing: 2px;
    text-transform: uppercase;
  }
  #sand {
    border: 2px solid #334;
    border-radius: 8px;
    cursor: crosshair;
    display: block;
    image-rendering: pixelated;
    background: #0d0d1a;
    box-shadow: 0 0 30px rgba(0,0,0,0.5), inset 0 0 60px rgba(0,0,0,0.3);
  }
  .controls {
    display: flex;
    gap: 8px;
    margin-top: 16px;
    flex-wrap: wrap;
    justify-content: center;
    align-items: center;
  }
  .mat-btn {
    padding: 8px 18px;
    border: 2px solid transparent;
    border-radius: 6px;
    font-size: 0.85rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.15s ease;
    text-transform: uppercase;
    letter-spacing: 1px;
    outline: none;
  }
  .mat-btn:hover { transform: translateY(-1px); filter: brightness(1.2); }
  .mat-btn:active { transform: translateY(1px); }
  .mat-btn.active { border-color: #fff; box-shadow: 0 0 12px rgba(255,255,255,0.3); }
  #mat-sand { background: #e2b86d; color: #1a1a2e; }
  #mat-water { background: #4a90d9; color: #fff; }
  #mat-wall { background: #6b6b6b; color: #fff; }
  #mat-acid { background: #7ec850; color: #1a1a2e; }
  #mat-empty { background: #2a2a3e; color: #aaa; }
  #clear {
    background: #c0392b;
    color: #fff;
    padding: 8px 24px;
    border: 2px solid transparent;
    border-radius: 6px;
    font-size: 0.85rem;
    font-weight: 600;
    cursor: pointer;
    text-transform: uppercase;
    letter-spacing: 1px;
    transition: all 0.15s ease;
    outline: none;
  }
  #clear:hover { background: #e74c3c; transform: translateY(-1px); }
  #clear:active { transform: translateY(1px); }
  .brush-size {
    display: flex;
    align-items: center;
    gap: 6px;
    margin-top: 10px;
    color: #888;
    font-size: 0.8rem;
  }
  .brush-size input[type=range] {
    width: 100px;
    accent-color: #4a90d9;
  }
</style>
</head>
<body>
<h1>Falling Sand</h1>
<canvas id="sand"></canvas>
<div class="controls">
  <button class="mat-btn active" id="mat-sand">Sand</button>
  <button class="mat-btn" id="mat-water">Water</button>
  <button class="mat-btn" id="mat-wall">Wall</button>
  <button class="mat-btn" id="mat-acid">Acid</button>
  <button class="mat-btn" id="mat-empty">Eraser</button>
  <button id="clear">Clear</button>
</div>
<div class="brush-size">
  <span>Brush:</span>
  <input type="range" id="brush-size" min="1" max="10" value="3">
  <span id="brush-val">3</span>
</div>

<script>
(function() {
  // Grid dimensions
  const W = 200;
  const H = 200;
  const CELL_SIZE = 3; // CSS pixels per cell → 600x600 canvas
  const canvas = document.getElementById('sand');
  const ctx = canvas.getContext('2d');
  canvas.width = W * CELL_SIZE;
  canvas.height = H * CELL_SIZE;
  canvas.style.width = (W * CELL_SIZE) + 'px';
  canvas.style.height = (H * CELL_SIZE) + 'px';

  // Material constants
  const EMPTY = 0, SAND = 1, WATER = 2, WALL = 3, ACID = 4;

  // Grid data
  let grid = new Uint8Array(W * H);
  // Image data for rendering
  let imageData = ctx.createImageData(W * CELL_SIZE, H * CELL_SIZE);
  let buf = imageData.data;

  // Current material
  let currentMat = SAND;
  let brushSize = 3;
  let painting = false;

  function idx(x, y) { return y * W + x; }

  function get(x, y) {
    if (x < 0 || x >= W || y < 0 || y >= H) return WALL;
    return grid[idx(x, y)];
  }

  function set(x, y, mat) {
    if (x < 0 || x >= W || y < 0 || y >= H) return;
    grid[idx(x, y)] = mat;
  }

  function clearGrid() {
    grid.fill(EMPTY);
  }

  // Color helpers
  function sandColor() {
    const v = Math.random() * 30 - 15;
    return [
      Math.min(255, Math.max(0, 226 + v)),
      Math.min(255, Math.max(0, 184 + v)),
      Math.min(255, Math.max(0, 109 + v))
    ];
  }
  function waterColor() {
    const v = Math.random() * 20 - 10;
    return [
      Math.min(255, Math.max(0, 74 + v)),
      Math.min(255, Math.max(0, 144 + v)),
      Math.min(255, Math.max(0, 217 + v))
    ];
  }
  function wallColor() {
    const v = Math.random() * 20 - 10;
    return [
      Math.min(255, Math.max(0, 107 + v)),
      Math.min(255, Math.max(0, 107 + v)),
      Math.min(255, Math.max(0, 107 + v))
    ];
  }
  function acidColor() {
    const v = Math.random() * 30 - 15;
    return [
      Math.min(255, Math.max(0, 126 + v)),
      Math.min(255, Math.max(0, 200 + v)),
      Math.min(255, Math.max(0, 80 + v))
    ];
  }
  function emptyColor() {
    return [13, 13, 26];
  }

  function render() {
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        let r, g, b;
        const mat = grid[idx(x, y)];
        switch (mat) {
          case SAND: [r, g, b] = sandColor(); break;
          case WATER: [r, g, b] = waterColor(); break;
          case WALL: [r, g, b] = wallColor(); break;
          case ACID: [r, g, b] = acidColor(); break;
          default: [r, g, b] = emptyColor(); break;
        }
        // Fill the cell block
        for (let dy = 0; dy < CELL_SIZE; dy++) {
          for (let dx = 0; dx < CELL_SIZE; dx++) {
            const px = (x * CELL_SIZE + dx);
            const py = (y * CELL_SIZE + dy);
            const pi = (py * W * CELL_SIZE + px) * 4;
            buf[pi] = r;
            buf[pi + 1] = g;
            buf[pi + 2] = b;
            buf[pi + 3] = 255;
          }
        }
      }
    }
    ctx.putImageData(imageData, 0, 0);
  }

  // Simulation step
  function step() {
    // Process bottom to top
    for (let y = H - 1; y >= 0; y--) {
      // Randomize left-right scan direction
      const leftToRight = Math.random() < 0.5;
      const startX = leftToRight ? 0 : W - 1;
      const endX = leftToRight ? W : -1;
      const stepX = leftToRight ? 1 : -1;

      for (let x = startX; x !== endX; x += stepX) {
        const i = idx(x, y);
        const mat = grid[i];

        if (mat === EMPTY || mat === WALL) continue;

        if (mat === SAND) {
          // Try to fall down
          if (y + 1 < H) {
            const below = idx(x, y + 1);
            const belowMat = grid[below];
            if (belowMat === EMPTY) {
              grid[below] = SAND;
              grid[i] = EMPTY;
            } else if (belowMat === WATER || belowMat === ACID) {
              // Swap
              grid[below] = SAND;
              grid[i] = belowMat;
            } else {
              // Try diagonal
              let dir1 = -1, dir2 = 1;
              if (Math.random() < 0.5) { dir1 = 1; dir2 = -1; }
              let moved = false;
              for (let d = 0; d < 2; d++) {
                const nx = x + (d === 0 ? dir1 : dir2);
                if (nx >= 0 && nx < W) {
                  const diagIdx = idx(nx, y + 1);
                  const diagMat = grid[diagIdx];
                  if (diagMat === EMPTY) {
                    grid[diagIdx] = SAND;
                    grid[i] = EMPTY;
                    moved = true;
                    break;
                  } else if (diagMat === WATER || diagMat === ACID) {
                    grid[diagIdx] = SAND;
                    grid[i] = diagMat;
                    moved = true;
                    break;
                  }
                }
              }
            }
          }
        } else if (mat === WATER) {
          // Try to fall down
          if (y + 1 < H) {
            const below = idx(x, y + 1);
            const belowMat = grid[below];
            if (belowMat === EMPTY) {
              grid[below] = WATER;
              grid[i] = EMPTY;
            } else {
              // Spread horizontally
              let dir1 = -1, dir2 = 1;
              if (Math.random() < 0.5) { dir1 = 1; dir2 = -1; }
              let moved = false;
              for (let d = 0; d < 2; d++) {
                const nx = x + (d === 0 ? dir1 : dir2);
                if (nx >= 0 && nx < W) {
                  const sideIdx = idx(nx, y);
                  if (grid[sideIdx] === EMPTY) {
                    grid[sideIdx] = WATER;
                    grid[i] = EMPTY;
                    moved = true;
                    break;
                  }
                }
              }
            }
          }
        } else if (mat === ACID) {
          // Try to fall down
          let moved = false;
          if (y + 1 < H) {
            const below = idx(x, y + 1);
            const belowMat = grid[below];
            if (belowMat === EMPTY) {
              grid[below] = ACID;
              grid[i] = EMPTY;
              moved = true;
            } else if (belowMat === SAND || belowMat === WALL) {
              // Dissolve
              grid[below] = EMPTY;
              // Acid may also disappear
              if (Math.random() < 0.5) {
                grid[i] = EMPTY;
              }
              moved = true;
            } else if (belowMat === WATER) {
              // Swap
              grid[below] = ACID;
              grid[i] = WATER;
              moved = true;
            }
          }
          if (!moved) {
            // Spread horizontally
            let dir1 = -1, dir2 = 1;
            if (Math.random() < 0.5) { dir1 = 1; dir2 = -1; }
            for (let d = 0; d < 2; d++) {
              const nx = x + (d === 0 ? dir1 : dir2);
              if (nx >= 0 && nx < W) {
                const sideIdx = idx(nx, y);
                const sideMat = grid[sideIdx];
                if (sideMat === EMPTY) {
                  grid[sideIdx] = ACID;
                  grid[i] = EMPTY;
                  break;
                } else if (sideMat === SAND || sideMat === WALL) {
                  grid[sideIdx] = EMPTY;
                  if (Math.random() < 0.5) {
                    grid[i] = EMPTY;
                  }
                  break;
                } else if (sideMat === WATER) {
                  grid[sideIdx] = ACID;
                  grid[i] = WATER;
                  break;
                }
              }
            }
          }
        }
      }
    }
  }

  // API
  window.sim = {
    get w() { return W; },
    get h() { return H; },
    tick(n) {
      for (let i = 0; i < n; i++) {
        step();
      }
      render();
    },
    get(x, y) {
      if (x < 0 || x >= W || y < 0 || y >= H) return 'wall';
      const mat = grid[idx(x, y)];
      return ['empty', 'sand', 'water', 'wall', 'acid'][mat];
    },
    set(x, y, material) {
      if (x < 0 || x >= W || y < 0 || y >= H) return;
      let mat;
      switch (material) {
        case 'empty': mat = EMPTY; break;
        case 'sand': mat = SAND; break;
        case 'water': mat = WATER; break;
        case 'wall': mat = WALL; break;
        case 'acid': mat = ACID; break;
        default: return;
      }
      grid[idx(x, y)] = mat;
    },
    clear() {
      clearGrid();
      render();
    }
  };

  // Material buttons
  const matButtons = {
    'mat-sand': SAND,
    'mat-water': WATER,
    'mat-wall': WALL,
    'mat-acid': ACID,
    'mat-empty': EMPTY
  };

  function setActiveMat(id) {
    document.querySelectorAll('.mat-btn').forEach(b => b.classList.remove('active'));
    document.getElementById(id).classList.add('active');
  }

  for (const [id, mat] of Object.entries(matButtons)) {
    document.getElementById(id).addEventListener('click', () => {
      setActiveMat(id);
      currentMat = mat;
    });
  }

  // Clear button
  document.getElementById('clear').addEventListener('click', () => {
    clearGrid();
    render();
  });

  // Brush size
  const brushSlider = document.getElementById('brush-size');
  const brushVal = document.getElementById('brush-val');
  brushSlider.addEventListener('input', () => {
    brushSize = parseInt(brushSlider.value);
    brushVal.textContent = brushSize;
  });

  // Painting
  function getCanvasPos(e) {
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    const clientX = e.touches ? e.touches[0].clientX : e.clientX;
    const clientY = e.touches ? e.touches[0].clientY : e.clientY;
    return {
      x: Math.floor((clientX - rect.left) * scaleX / CELL_SIZE),
      y: Math.floor((clientY - rect.top) * scaleY / CELL_SIZE)
    };
  }

  function paint(cx, cy) {
    const r = brushSize;
    for (let dy = -r; dy <= r; dy++) {
      for (let dx = -r; dx <= r; dx++) {
        if (dx * dx + dy * dy > r * r) continue;
        const nx = cx + dx;
        const ny = cy + dy;
        if (nx >= 0 && nx < W && ny >= 0 && ny < H) {
          if (currentMat === EMPTY) {
            grid[idx(nx, ny)] = EMPTY;
          } else {
            // Don't overwrite walls with other materials unless eraser
            if (grid[idx(nx, ny)] !== WALL || currentMat === WALL) {
              grid[idx(nx, ny)] = currentMat;
            }
          }
        }
      }
    }
  }

  canvas.addEventListener('mousedown', (e) => {
    painting = true;
    const pos = getCanvasPos(e);
    paint(pos.x, pos.y);
  });
  canvas.addEventListener('mousemove', (e) => {
    if (!painting) return;
    const pos = getCanvasPos(e);
    paint(pos.x, pos.y);
  });
  canvas.addEventListener('mouseup', () => { painting = false; });
  canvas.addEventListener('mouseleave', () => { painting = false; });

  // Touch support
  canvas.addEventListener('touchstart', (e) => {
    e.preventDefault();
    painting = true;
    const pos = getCanvasPos(e);
    paint(pos.x, pos.y);
  });
  canvas.addEventListener('touchmove', (e) => {
    e.preventDefault();
    if (!painting) return;
    const pos = getCanvasPos(e);
    paint(pos.x, pos.y);
  });
  canvas.addEventListener('touchend', () => { painting = false; });

  // Animation loop
  let lastTime = 0;
  const TICKS_PER_FRAME = 3;
  let accumulator = 0;

  function animate(time) {
    if (!lastTime) lastTime = time;
    const dt = time - lastTime;
    lastTime = time;
    accumulator += dt;
    // ~60 steps per second
    const stepInterval = 1000 / 60;
    while (accumulator >= stepInterval) {
      step();
      accumulator -= stepInterval;
    }
    render();
    requestAnimationFrame(animate);
  }

  render();
  requestAnimationFrame(animate);
})();
</script>
</body>
</html>
